import React, { useState, useEffect, useCallback } from 'react';
import api from '../api/api';
import { FaRunning, FaAppleAlt, FaBrain, FaSpinner, FaExchangeAlt, FaUtensils, FaCheckSquare } from 'react-icons/fa';

// Mock Modal Component for simplicity
const MockModal = ({ title, content, onClose }) => {
    if (!content) return null;
    return (
        <div className="fixed inset-0 bg-black bg-opacity-75 flex items-center justify-center z-50 p-4">
            <div className="bg-[#1E1E1E] p-6 rounded-xl border border-ai-green w-full max-w-lg shadow-2xl">
                <h3 className="text-xl font-bold text-ai-green mb-4 border-b border-gray-700 pb-2">{title}</h3>
                <div className="text-gray-300 space-y-3 max-h-96 overflow-y-auto">
                    {typeof content === 'string' ? <p>{content}</p> : content}
                </div>
                <button 
                    onClick={onClose} 
                    className="mt-6 w-full py-2 bg-accent-blue rounded text-white font-semibold hover:bg-ai-green hover:text-black transition duration-200"
                >
                    Close
                </button>
            </div>
        </div>
    );
};

const Recommendations = ({ profile, user }) => {
    const [recommendations, setRecommendations] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [modal, setModal] = useState(null); // State for modal content

    // State to track completed tasks (for Plan Adherence Score)
    const [completedTasks, setCompletedTasks] = useState(() => {
        // Load initial state from localStorage or default to empty object
        const saved = localStorage.getItem('planAdherence');
        return saved ? JSON.parse(saved) : {};
    });

    // Save completed tasks to localStorage whenever it changes
    useEffect(() => {
        localStorage.setItem('planAdherence', JSON.stringify(completedTasks));
    }, [completedTasks]);

    const handleTaskCompletion = (planType, index) => {
        const key = `${planType}-${index}`;
        setCompletedTasks(prev => ({
            ...prev,
            [key]: !prev[key] // Toggle state
        }));
    };

    const handleSwap = async (item, planType, index) => {
        setLoading(true);
        try {
            // Call new backend swap endpoint
            const response = await api.post('/recommendations/swap', {
                itemToSwap: item,
                goal: profile.goal
            });
            
            // Show the swap result in a modal
            setModal({
                title: "Meal Swap Suggestion",
                content: (
                    <div className="space-y-2">
                        <p className="font-bold">Original: {item}</p>
                        <p className="text-ai-green font-semibold">Suggested Swap (Indian Vegetarian):</p>
                        <p className="text-lg">{response.data.suggestedSwap}</p>
                        <p className="text-sm text-gray-500">Note: This swap maintains the required macro balance for your goal.</p>
                    </div>
                )
            });

        } catch (err) {
            setModal({ title: "Swap Failed", content: "Could not generate a swap at this time. Try again later." });
        } finally {
            setLoading(false);
        }
    };
    
    const handleRecipeView = (item) => {
        setModal({
            title: `Recipe: ${item}`,
            content: (
                <div className="space-y-2">
                    <p className="font-semibold">Mock Recipe Steps for {item}:</p>
                    <ol className="list-decimal ml-4 text-sm">
                        <li>Gather ingredients (Mocks only).</li>
                        <li>Prep time: 15 mins. Cook time: 30 mins.</li>
                        <li>Full instructions link: <a href="#mock-recipe-link" className="text-accent-blue hover:underline">View Tutorial Video</a> (Mock Link)</li>
                    </ol>
                </div>
            )
        });
    };

    const fetchRecommendations = useCallback(async () => {
        setLoading(true);
        setError(null);
        setRecommendations(null);

        const { goal, latestRiskScore, dailyCalorieTarget } = profile;

        if (!goal || !dailyCalorieTarget) {
            setError("Please complete your Profile (Goal & Metrics) and run a Health Risk Check first.");
            setLoading(false);
            return;
        }

        try {
            const response = await api.post('/recommendations/generate', {
                goal,
                latestRiskScore,
                dailyCalorieTarget
            });
            
            setRecommendations(response.data.recommendations);
        } catch (err) {
            console.error('Error fetching recommendations:', err.response?.data || err);
            setError(err.response?.data?.message || "Failed to load personalized plans.");
        } finally {
            setLoading(false);
        }
    }, [profile]);

    useEffect(() => {
        fetchRecommendations();
    }, [fetchRecommendations]);

    if (loading && !recommendations) {
        return <div className="p-8 text-center text-ai-green"><FaSpinner className="animate-spin inline mr-2" /> Generating personalized plans...</div>;
    }

    if (error) {
        return <div className="p-8 text-red-400 border border-red-700 rounded-lg">{error}</div>;
    }
    
    if (!recommendations || Object.keys(recommendations).length === 0) {
        return <div className="p-8 text-gray-500">No specific recommendations available.</div>;
    }

    return (
        <div className="space-y-8">
            <MockModal title={modal?.title} content={modal?.content} onClose={() => setModal(null)} />

            <div className="flex items-center space-x-3 text-lg font-medium text-gray-300">
                <FaBrain className="text-ai-green text-xl" />
                <p>Plans tailored for **{profile.goal?.toUpperCase() || 'MAINTAIN'}** based on your **{profile.latestRiskScore || 'N/A'} Risk** level.</p>
            </div>
            
            {/* Diet Plan Card */}
            <div className="bg-[#161B22] p-6 rounded-xl border border-ai-green/50 shadow-md">
                <h3 className="text-2xl font-bold mb-4 text-yellow-400 flex items-center">
                    <FaAppleAlt className="mr-3" /> Diet Plan (Target: {profile.dailyCalorieTarget} kcal)
                </h3>
                <ul className="space-y-3 text-gray-300">
                    {recommendations.dietPlan.map((item, index) => {
                        const isMeal = item.includes('Meal') || item.includes('Breakfast') || item.includes('Lunch') || item.includes('Dinner');
                        const key = `diet-${index}`;
                        const isCompleted = completedTasks[key];

                        return (
                            <li key={index} className={`flex items-start justify-between p-2 rounded-lg transition-colors ${isCompleted ? 'bg-ai-green/20 text-ai-green' : 'hover:bg-gray-800'}`}>
                                <div className="flex items-start flex-1 mr-4">
                                    <button 
                                        type="button"
                                        onClick={() => handleTaskCompletion('diet', index)}
                                        className={`mt-1 mr-3 text-lg ${isCompleted ? 'text-ai-green' : 'text-gray-600 hover:text-accent-blue'}`}
                                    >
                                        <FaCheckSquare />
                                    </button>
                                    <span className={isCompleted ? 'line-through opacity-75' : ''}>
                                        {item}
                                    </span>
                                </div>
                                {isMeal && (
                                    <div className="flex space-x-2 text-sm ml-auto">
                                        <button 
                                            onClick={() => handleRecipeView(item)}
                                            className="text-yellow-400 flex items-center hover:text-yellow-300"
                                            title="View Recipe/Instructions"
                                        >
                                            <FaUtensils className="mr-1" /> Recipe
                                        </button>
                                        <button 
                                            onClick={() => handleSwap(item, 'diet', index)}
                                            className="text-accent-blue flex items-center hover:text-ai-green"
                                            title="Swap Meal"
                                            disabled={loading}
                                        >
                                            <FaExchangeAlt className="mr-1" /> Swap
                                        </button>
                                    </div>
                                )}
                            </li>
                        );
                    })}
                </ul>
            </div>

            {/* Exercise Plan Card */}
            <div className="bg-[#161B22] p-6 rounded-xl border border-accent-blue/50 shadow-md">
                <h3 className="text-2xl font-bold mb-4 text-blue-400 flex items-center">
                    <FaRunning className="mr-3" /> Weekly Exercise Plan
                </h3>
                <ul className="space-y-3 text-gray-300">
                    {recommendations.exercisePlan.map((item, index) => {
                        const key = `exercise-${index}`;
                        const isCompleted = completedTasks[key];
                        return (
                            <li key={index} className={`flex items-start p-2 rounded-lg transition-colors ${isCompleted ? 'bg-ai-green/20 text-ai-green' : 'hover:bg-gray-800'}`}>
                                <button 
                                    type="button"
                                    onClick={() => handleTaskCompletion('exercise', index)}
                                    className={`mt-1 mr-3 text-lg ${isCompleted ? 'text-ai-green' : 'text-gray-600 hover:text-accent-blue'}`}
                                >
                                    <FaCheckSquare />
                                </button>
                                <span className={isCompleted ? 'line-through opacity-75' : ''}>
                                    {item}
                                </span>
                            </li>
                        );
                    })}
                </ul>
            </div>
        </div>
    );
};

export default Recommendations;
